// ---- helpers ----
function decodeBase64Url(s) {
  if (!s || typeof s !== 'string') return '';
  s = s.replace(/-/g, '+').replace(/_/g, '/');
  const pad = s.length % 4 ? 4 - (s.length % 4) : 0;
  return Buffer.from(s + '='.repeat(pad), 'base64').toString('utf8');
}

function extractText(payload) {
  const texts = [];
  (function walk(part) {
    if (!part) return;
    const mime = part.mimeType || '';
    if (part.body && part.body.data && (mime === 'text/plain' || mime === 'text/html')) {
      texts.push(decodeBase64Url(part.body.data));
    }
    (part.parts || []).forEach(walk);
  })(payload);
  const plain = texts.find(t => !t.trim().startsWith('<')) || texts[0] || '';
  return (plain || '').trim();
}

function headersToMap(arr = []) {
  return arr.reduce((acc, h) => {
    if (h && h.name) acc[h.name.toLowerCase()] = h.value || '';
    return acc;
  }, {});
}

function canonicalizeSubject(s = '') {
  return s.replace(/^\s*(re|fw|fwd)\s*:/i, '').trim();
}

function collectMessages(j) {
  if (Array.isArray(j?.messages)) return j.messages;         // threads.get
  if (Array.isArray(j?.body?.messages)) return j.body.messages; // http wrapper
  if (j?.payload) return [j];                                // messages.get
  return [];
}

// ---- main ----
const input = items[0].json || items[0];
const rawMsgs = collectMessages(input);

// Normalize: {date, from, subject, body}
const msgs = rawMsgs.map(m => {
  const headers = headersToMap(m.payload?.headers || []);
  const dateIso = m.internalDate
    ? new Date(Number(m.internalDate)).toISOString()
    : (headers['date'] ? new Date(headers['date']).toISOString() : '');
  const subject = headers['subject'] || '';
  const body = extractText(m.payload) || m.snippet || '';
  return { date: dateIso, from: headers['from'] || '', subject, body: body.trim() };
});

// If nothing found, return empty fields so downstream nodes don't crash
if (!msgs.length) {
  return [{ json: { thread_subject: '', thread_text: '' } }];
}

// Sort chronological (oldest → newest)
msgs.sort((a, b) => (a.date > b.date ? 1 : -1));

// Build timeline
const thread_text = msgs.map((m, i) =>
  `--- Message ${i + 1} ---\nDate: ${m.date}\nFrom: ${m.from}\nSubject: ${m.subject}\n\n${m.body}\n`
).join('\n');

// Canonical subject (prefer original/first; fallback to last)
const firstSub = msgs[0].subject || '';
const lastSub  = msgs[msgs.length - 1].subject || '';
const thread_subject = canonicalizeSubject(firstSub) || canonicalizeSubject(lastSub);

// Output
return [{ json: { thread_subject, thread_text } }];

// ---- Parse AI output (works for plain JSON or "```json ... ```" string) ----
function stripFences(s){
  return typeof s === 'string'
    ? s.replace(/^```(?:json)?\s*/i,'').replace(/```$/,'').trim()
    : s;
}
let ai = $json;
if (typeof ai === 'string') ai = JSON.parse(stripFences(ai));
if (ai && typeof ai === 'object' && typeof ai.output === 'string') {
  ai = JSON.parse(stripFences(ai.output));
}

// ---- Optional: get thread URL from your builder node (rename if needed) ----
const tb = ($items('Code', 0, 0)[0] || { json:{} }).json;
const gmailUrl = tb.thread_id ? `https://mail.google.com/mail/u/0/#inbox/${tb.thread_id}` : '';

// ---- Status emoji map ----
const emojiMap = {
  'Approved':'✅', 'Needs Review':'🟡', 'In Progress':'🛠️',
  'Blocked':'🔴', 'Draft':'📝', 'Superseded':'🗂️', 'Not a Playbook':'❓'
};
const statusEmoji = emojiMap[ai.status] || '';

// ---- Format next actions ----
const next = Array.isArray(ai.next_actions) && ai.next_actions.length
  ? ai.next_actions.map((x,i)=>`${i+1}. ${x}`).join('\n')
  : '—';

// ---- Build Slack message ----
const text =
  `<!channel> Please see details of a playbook update below:\n` +
  `*Subject:* ${ai.subject || '—'}\n` +
  `*Status:* ${statusEmoji} ${ai.status || '—'}\n` +
  `*Owner:* ${ai.owner || '—'}\n` +
  `*Due:* ${ai.due_date || '—'}\n` +
  `*Next:*\n${next}\n` +
  `\n\nPlease update the status accordingly. Thank you.`;

// ---- Output for Slack node ----
return [{ json: { ...ai, slack_message: text } }];
